import React, { useState, useRef, useEffect, useMemo } from 'react';
import type { WarehouseColumnConfig, WarehouseCategoryType, WarehouseMetricType } from '../../types';
import ModalWrapper from '../modals/ModalWrapper';
import { Icon } from '../common/Icon';
import SearchableSelect from '../common/SearchableSelect';
import { WAREHOUSE_METRIC_TYPE_MAP, WAREHOUSE_HEADER_COLORS, DEFAULT_WAREHOUSE_COLUMNS } from '../../constants';

interface SettingsModalProps {
    isOpen: boolean;
    onClose: () => void;
    columns: WarehouseColumnConfig[];
    onSave: (newColumns: WarehouseColumnConfig[]) => void;
    allIndustries: string[];
    allGroups: string[];
    allManufacturers: string[];
}

const WarehouseSettingsModal: React.FC<SettingsModalProps> = ({ isOpen, onClose, columns, onSave, allIndustries, allGroups, allManufacturers }) => {
    const [internalColumns, setInternalColumns] = useState<WarehouseColumnConfig[]>([]);
    const [view, setView] = useState<'picker' | 'form'>('picker');

    // Form state
    const [editingColumn, setEditingColumn] = useState<WarehouseColumnConfig | null>(null);
    const [mainHeader, setMainHeader] = useState('');
    const [subHeader, setSubHeader] = useState('');
    const [categoryType, setCategoryType] = useState<WarehouseCategoryType>('industry');
    const [categoryName, setCategoryName] = useState('');
    const [manufacturerName, setManufacturerName] = useState('');
    const [productCodesInput, setProductCodesInput] = useState<string>('');
    const [metricType, setMetricType] = useState<WarehouseMetricType>('quantity');

    const mainHeaderInputRef = useRef<HTMLInputElement>(null);

    useEffect(() => {
        if (isOpen) {
            const sortedColumns = [...columns].sort((a, b) => a.order - b.order);
            setInternalColumns(sortedColumns);
            setView('picker');
            resetForm(false);
        }
    }, [isOpen, columns]);

    useEffect(() => {
        if (view === 'form' && editingColumn === null) {
            mainHeaderInputRef.current?.focus();
        }
    }, [view, editingColumn]);

    const groupedColumns = useMemo(() => {
        return internalColumns.reduce<Record<string, WarehouseColumnConfig[]>>((acc, col) => {
            const key = col.mainHeader || 'Chưa phân loại';
            if (!acc[key]) {
                acc[key] = [];
            }
            acc[key].push(col);
            return acc;
        }, {});
    }, [internalColumns]);

    const resetForm = (switchToPicker = true) => {
        setEditingColumn(null);
        setMainHeader(''); setSubHeader(''); setCategoryType('industry');
        setCategoryName(''); setManufacturerName(''); setMetricType('quantity');
        setProductCodesInput('');
        if (switchToPicker) {
            setView('picker');
        }
    };

    const handleEdit = (column: WarehouseColumnConfig) => {
        setEditingColumn(column);
        setMainHeader(column.mainHeader);
        setSubHeader(column.subHeader);
        setCategoryType(column.categoryType || 'industry');
        setCategoryName(column.categoryName || '');
        setManufacturerName(column.manufacturerName || '');
        setProductCodesInput(column.productCodes?.join(', ') || '');
        setMetricType(column.metricType || 'quantity');
        setView('form');
    };

    const handleSaveAndClose = () => {
        const reorderedColumns = internalColumns.map((c, i) => ({ ...c, order: i }));
        onSave(reorderedColumns);
        onClose();
    };

    const handleToggleVisibility = (id: string) => {
        setInternalColumns(prev => prev.map(c => c.id === id ? { ...c, isVisible: !c.isVisible } : c));
    };

    const handleDelete = (id: string) => {
        if (window.confirm('Bạn có chắc chắn muốn xóa cột tùy chỉnh này?')) {
            setInternalColumns(prev => prev.filter(c => c.id !== id));
        }
    };

    const handleDeleteGroup = (groupName: string) => {
        if (window.confirm(`Bạn có chắc chắn muốn xóa nhóm "${groupName}" và tất cả các cột bên trong?`)) {
            setInternalColumns(prev => prev.filter(c => c.mainHeader !== groupName));
        }
    };

    const handleToggleGroupVisibility = (mainHeader: string, shouldBeVisible: boolean) => {
        setInternalColumns(prev => prev.map(c => c.mainHeader === mainHeader ? { ...c, isVisible: shouldBeVisible } : c));
    };

    const handleSaveColumn = (e: React.FormEvent) => {
        e.preventDefault();

        if (!mainHeader.trim() || !subHeader.trim()) {
            alert('Vui lòng điền đầy đủ Tiêu đề chính và Tiêu đề phụ.');
            return;
        }

        const productCodes = productCodesInput.split(/[\s,]+/).map(code => code.trim()).filter(Boolean);

        const newColumnData = {
            mainHeader: mainHeader.trim(), subHeader: subHeader.trim(), categoryType, 
            categoryName: categoryName || undefined, 
            manufacturerName: manufacturerName || undefined, 
            productCodes: productCodes.length > 0 ? productCodes : undefined,
            metricType 
        };

        if (editingColumn) {
            setInternalColumns(prev => prev.map(col => col.id === editingColumn.id ? { ...col, ...newColumnData } : col));
        } else {
            const newColumn: WarehouseColumnConfig = {
                id: `custom_${Date.now()}`,
                order: internalColumns.length, isVisible: true, isCustom: true,
                ...newColumnData
            };
            setInternalColumns(prev => [...prev, newColumn]);
        }
        resetForm();
    };

    const handleSelectAll = (select: boolean) => {
        setInternalColumns(prev => prev.map(c => ({...c, isVisible: select})));
    };

    const handleRestoreDefaults = () => {
        if (window.confirm('Thao tác này sẽ xóa tất cả các tùy chỉnh và khôi phục lại bố cục cột mặc định. Bạn có chắc chắn?')) {
            setInternalColumns([...DEFAULT_WAREHOUSE_COLUMNS]);
            resetForm();
        }
    };

    // Mapping colors for the picker UI
    const groupColorMap: Record<string, { bg: string, text: string, border: string }> = {
        'Doanh Thu': { bg: 'bg-blue-50 dark:bg-blue-900/20', text: 'text-blue-700 dark:text-blue-300', border: 'border-blue-200 dark:border-blue-800' },
        'TRAFFIC & TỶ LỆ TC/DT': { bg: 'bg-cyan-50 dark:bg-cyan-900/20', text: 'text-cyan-700 dark:text-cyan-300', border: 'border-cyan-200 dark:border-cyan-800' },
        'S.PHẨM CHÍNH': { bg: 'bg-teal-50 dark:bg-teal-900/20', text: 'text-teal-700 dark:text-teal-300', border: 'border-teal-200 dark:border-teal-800' },
        'SL BÁN KÈM': { bg: 'bg-violet-50 dark:bg-violet-900/20', text: 'text-violet-700 dark:text-violet-300', border: 'border-violet-200 dark:border-violet-800' },
        'DT THỰC NGÀNH HÀNG': { bg: 'bg-purple-50 dark:bg-purple-900/20', text: 'text-purple-700 dark:text-purple-300', border: 'border-purple-200 dark:border-purple-800' },
        'Phụ Kiện': { bg: 'bg-amber-50 dark:bg-amber-900/20', text: 'text-amber-700 dark:text-amber-300', border: 'border-amber-200 dark:border-amber-800' },
        'Gia Dụng': { bg: 'bg-orange-50 dark:bg-orange-900/20', text: 'text-orange-700 dark:text-orange-300', border: 'border-orange-200 dark:border-orange-800' },
        'DEFAULT': { bg: 'bg-slate-50 dark:bg-slate-800/50', text: 'text-slate-700 dark:text-slate-300', border: 'border-slate-200 dark:border-slate-700' },
    };

    const renderPickerView = () => (
        <>
            <div className="flex flex-wrap items-center justify-between gap-4 mb-6">
                <div className="flex items-center gap-2 p-1 bg-slate-100 dark:bg-slate-800 rounded-xl border border-slate-200 dark:border-slate-700">
                    <button onClick={() => handleSelectAll(true)} className="px-3 py-1.5 text-xs font-bold text-slate-600 dark:text-slate-300 hover:bg-white dark:hover:bg-slate-700 rounded-lg transition-all">Hiện tất cả</button>
                    <div className="w-px h-4 bg-slate-300 dark:bg-slate-600"></div>
                    <button onClick={() => handleSelectAll(false)} className="px-3 py-1.5 text-xs font-bold text-slate-500 hover:text-slate-700 dark:hover:text-slate-200 hover:bg-white dark:hover:bg-slate-700 rounded-lg transition-all">Ẩn tất cả</button>
                </div>
                 <button onClick={() => { resetForm(false); setView('form'); }} className="flex items-center gap-2 px-5 py-2.5 rounded-xl text-sm font-bold text-white bg-indigo-600 hover:bg-indigo-700 active:scale-95 transition-all shadow-lg shadow-indigo-200 dark:shadow-none">
                    <Icon name="plus" size={4} /> Thêm cột mới
                </button>
            </div>

             <div className="grid grid-cols-1 md:grid-cols-2 xl:grid-cols-3 gap-5">
                 {Object.entries(groupedColumns).map(([mainHeader, cols]) => {
                    if (!Array.isArray(cols)) return null;
                    const visibleCount = cols.filter(c => c.isVisible).length;
                    const isCustomGroup = cols.every(c => c.isCustom);
                    const styles = groupColorMap[mainHeader] || groupColorMap.DEFAULT;

                    return (
                        <div key={mainHeader} className={`group flex flex-col h-full rounded-[1.5rem] border ${styles.border} ${styles.bg} transition-all duration-300 hover:shadow-lg hover:-translate-y-1 overflow-hidden`}>
                            <div className="p-4 flex justify-between items-start border-b border-white/50 dark:border-slate-700/50">
                                <div>
                                    <h4 className={`text-sm font-black uppercase tracking-wide ${styles.text}`}>{mainHeader}</h4>
                                    <div className="mt-1 flex items-center gap-2">
                                        <span className="text-[10px] font-bold px-2 py-0.5 bg-white/60 dark:bg-black/20 rounded-md backdrop-blur-sm text-slate-600 dark:text-slate-300">
                                            {visibleCount}/{cols.length} hiển thị
                                        </span>
                                    </div>
                                </div>
                                <div className="flex items-center gap-1 opacity-0 group-hover:opacity-100 transition-opacity">
                                    <button onClick={() => handleToggleGroupVisibility(mainHeader, true)} title="Hiện nhóm" className="p-1.5 bg-white/80 dark:bg-slate-800/80 hover:bg-white text-emerald-600 rounded-lg shadow-sm backdrop-blur-sm"><Icon name="eye" size={3.5}/></button>
                                    <button onClick={() => handleToggleGroupVisibility(mainHeader, false)} title="Ẩn nhóm" className="p-1.5 bg-white/80 dark:bg-slate-800/80 hover:bg-white text-slate-500 rounded-lg shadow-sm backdrop-blur-sm"><Icon name="eye-off" size={3.5}/></button>
                                    {isCustomGroup && (
                                        <button onClick={() => handleDeleteGroup(mainHeader)} title="Xóa nhóm" className="p-1.5 bg-white/80 dark:bg-slate-800/80 hover:bg-white text-red-500 rounded-lg shadow-sm backdrop-blur-sm"><Icon name="trash-2" size={3.5}/></button>
                                    )}
                                </div>
                            </div>

                            <div className="p-4 flex flex-wrap content-start gap-2 flex-grow">
                                {cols.map(col => (
                                    <div 
                                        key={col.id} 
                                        className={`relative group/item inline-flex items-center gap-2 pl-3 pr-2 py-1.5 rounded-xl text-xs font-bold border transition-all cursor-pointer select-none
                                            ${col.isVisible 
                                                ? 'bg-white dark:bg-slate-800 border-slate-200 dark:border-slate-600 text-slate-800 dark:text-slate-100 shadow-sm' 
                                                : 'bg-slate-100/50 dark:bg-slate-900/30 border-transparent text-slate-400 dark:text-slate-500'
                                            }`}
                                        onClick={() => handleToggleVisibility(col.id)}
                                    >
                                        <div className={`w-2 h-2 rounded-full ${col.isVisible ? 'bg-emerald-500' : 'bg-slate-300 dark:bg-slate-600'}`}></div>
                                        <span>{col.subHeader}</span>

                                        {col.isCustom && (
                                            <div className="flex items-center gap-1 ml-1 pl-1 border-l border-slate-200 dark:border-slate-700">
                                                <button onClick={(e) => { e.stopPropagation(); handleEdit(col); }} className="p-1 hover:bg-blue-100 dark:hover:bg-blue-900/50 text-blue-500 rounded"><Icon name="edit-3" size={3} /></button>
                                                <button onClick={(e) => { e.stopPropagation(); handleDelete(col.id); }} className="p-1 hover:bg-red-100 dark:hover:bg-red-900/50 text-red-500 rounded"><Icon name="x" size={3} /></button>
                                            </div>
                                        )}
                                    </div>
                                ))}
                            </div>
                        </div>
                    )
                })}
            </div>
        </>
    );

    const renderFormView = () => (
        <form onSubmit={handleSaveColumn} className="flex flex-col h-full">
            <div className="flex items-center gap-4 mb-6">
                <button type="button" onClick={() => resetForm()} className="p-2 -ml-2 rounded-full hover:bg-slate-100 dark:hover:bg-slate-800 transition-colors">
                    <Icon name="arrow-left" size={6} />
                </button>
                <h3 className="font-black text-xl text-slate-800 dark:text-slate-100 uppercase tracking-tight">{editingColumn ? `Sửa cột: ${editingColumn.subHeader}` : 'Thêm cột mới'}</h3>
            </div>

            <div className="flex-grow overflow-y-auto pr-2 custom-scrollbar space-y-6">

                {/* Block 1: Identification */}
                <div className="p-6 bg-white dark:bg-slate-800 rounded-[1.5rem] border border-slate-200 dark:border-slate-700 shadow-sm">
                    <h4 className="text-xs font-black text-slate-400 uppercase tracking-widest mb-4 flex items-center gap-2">
                        <Icon name="tag" size={4} /> Định danh
                    </h4>
                    <div className="grid grid-cols-1 md:grid-cols-2 gap-5">
                        <div>
                            <label className="block text-sm font-bold text-slate-700 dark:text-slate-300 mb-2">Tiêu đề nhóm (Cha)</label>
                            <input ref={mainHeaderInputRef} value={mainHeader} onChange={e => setMainHeader(e.target.value)} placeholder="VD: Phụ Kiện" className="w-full h-12 px-4 rounded-xl bg-slate-50 dark:bg-slate-900 border border-slate-200 dark:border-slate-700 focus:ring-2 focus:ring-indigo-500 focus:border-indigo-500 font-semibold transition-all" required />
                        </div>
                        <div>
                            <label className="block text-sm font-bold text-slate-700 dark:text-slate-300 mb-2">Tiêu đề cột (Con)</label>
                            <input value={subHeader} onChange={e => setSubHeader(e.target.value)} placeholder="VD: SL Camera" className="w-full h-12 px-4 rounded-xl bg-slate-50 dark:bg-slate-900 border border-slate-200 dark:border-slate-700 focus:ring-2 focus:ring-indigo-500 focus:border-indigo-500 font-semibold transition-all" required />
                        </div>
                    </div>
                </div>

                {/* Block 2: Logic */}
                <div className="p-6 bg-white dark:bg-slate-800 rounded-[1.5rem] border border-slate-200 dark:border-slate-700 shadow-sm">
                    <h4 className="text-xs font-black text-slate-400 uppercase tracking-widest mb-4 flex items-center gap-2">
                        <Icon name="database" size={4} /> Nguồn dữ liệu
                    </h4>
                    <div className="grid grid-cols-1 md:grid-cols-2 gap-5">
                        <div>
                            <label className="block text-sm font-bold text-slate-700 dark:text-slate-300 mb-2">Loại danh mục</label>
                            <div className="relative">
                                <select value={categoryType} onChange={e => { setCategoryType(e.target.value as WarehouseCategoryType); setCategoryName(''); }} className="w-full h-12 px-4 rounded-xl bg-slate-50 dark:bg-slate-900 border border-slate-200 dark:border-slate-700 focus:ring-2 focus:ring-indigo-500 focus:border-indigo-500 font-semibold appearance-none">
                                    <option value="industry">Theo Ngành hàng (Lớn)</option>
                                    <option value="group">Theo Nhóm hàng (Nhỏ)</option>
                                </select>
                                <div className="absolute right-4 top-1/2 -translate-y-1/2 pointer-events-none text-slate-500"><Icon name="chevron-down" size={4}/></div>
                            </div>
                        </div>

                        <SearchableSelect
                            label="Danh mục chính"
                            options={(categoryType === 'industry' ? allIndustries : allGroups)}
                            value={categoryName}
                            onChange={setCategoryName}
                            placeholder="-- Chọn danh mục --"
                        />

                        <div>
                            <label className="block text-sm font-bold text-slate-700 dark:text-slate-300 mb-2">Chỉ số cần tính</label>
                            <div className="grid grid-cols-3 gap-2 p-1 bg-slate-50 dark:bg-slate-900 rounded-xl border border-slate-200 dark:border-slate-700">
                                {Object.entries(WAREHOUSE_METRIC_TYPE_MAP).map(([key, label]) => (
                                    <button
                                        type="button"
                                        key={key}
                                        onClick={() => setMetricType(key as WarehouseMetricType)}
                                        className={`py-2 text-xs font-bold rounded-lg transition-all ${metricType === key ? 'bg-white dark:bg-slate-700 text-indigo-600 shadow-sm' : 'text-slate-500 hover:text-slate-700'}`}
                                    >
                                        {label}
                                    </button>
                                ))}
                            </div>
                        </div>

                        <SearchableSelect
                            label="Nhà sản xuất (Tùy chọn)"
                            options={allManufacturers}
                            value={manufacturerName}
                            onChange={setManufacturerName}
                            placeholder="-- Tất cả --"
                        />
                    </div>

                    <div className="mt-5">
                        <label className="block text-sm font-bold text-slate-700 dark:text-slate-300 mb-2">Mã sản phẩm (Tùy chọn nâng cao)</label>
                        <textarea 
                            value={productCodesInput} 
                            onChange={e => setProductCodesInput(e.target.value)} 
                            placeholder="Nhập mã nhóm hàng cụ thể, cách nhau bằng dấu phẩy. Ví dụ: 1234, 5678" 
                            rows={2} 
                            className="w-full p-4 rounded-xl bg-slate-50 dark:bg-slate-900 border border-slate-200 dark:border-slate-700 focus:ring-2 focus:ring-indigo-500 focus:border-indigo-500 font-mono text-sm transition-all" 
                        />
                        <p className="text-xs text-slate-400 mt-2 font-medium">* Chỉ dùng khi muốn lọc chi tiết hơn cả Nhóm hàng.</p>
                    </div>
                </div>
            </div>

            <div className="pt-6 mt-2 border-t border-slate-200 dark:border-slate-700 flex gap-4">
                <button type="button" onClick={() => resetForm()} className="flex-1 h-14 rounded-2xl font-bold text-slate-600 bg-slate-100 hover:bg-slate-200 dark:bg-slate-800 dark:text-slate-300 dark:hover:bg-slate-700 transition-all">
                    Hủy bỏ
                </button>
                <button type="submit" className="flex-1 h-14 rounded-2xl font-black text-white bg-indigo-600 hover:bg-indigo-700 active:scale-95 shadow-xl shadow-indigo-200 dark:shadow-none transition-all flex items-center justify-center gap-2">
                    <Icon name={editingColumn ? 'save' : 'plus-circle'} size={5} />
                    {editingColumn ? 'Lưu thay đổi' : 'Thêm cột này'}
                </button>
            </div>
        </form>
    );

    return (
        <ModalWrapper 
            isOpen={isOpen} 
            onClose={onClose} 
            title="Tùy Chỉnh Cột Báo Cáo" 
            subTitle="Thiết kế bố cục hiển thị theo nhu cầu quản trị" 
            titleColorClass="text-indigo-600 dark:text-indigo-400" 
            maxWidthClass="max-w-6xl"
        >
            <div className="p-8 flex flex-col max-h-[85vh] min-h-[60vh] bg-slate-50/50 dark:bg-slate-950/50 backdrop-blur-md">
                <div className="flex-grow overflow-y-auto custom-scrollbar px-1">
                   {view === 'picker' ? renderPickerView() : renderFormView()}
                </div>

                {view === 'picker' && (
                    <div className="pt-6 mt-6 border-t border-slate-200 dark:border-slate-700 flex justify-between items-center">
                        <button onClick={handleRestoreDefaults} className="text-xs font-bold text-slate-400 hover:text-amber-600 transition-colors flex items-center gap-1.5">
                            <Icon name="history" size={3.5} /> Khôi phục mặc định
                        </button>
                        <button onClick={handleSaveAndClose} className="px-8 py-4 rounded-2xl text-sm font-black text-white bg-slate-900 hover:bg-black dark:bg-white dark:text-slate-900 dark:hover:bg-slate-200 shadow-xl transition-all active:scale-95">
                            Hoàn tất & Đóng
                        </button>
                    </div>
                )}
            </div>
        </ModalWrapper>
    );
};

export default WarehouseSettingsModal;

import React, { useState, useRef, useEffect, useMemo } from 'react';
import type { WarehouseColumnConfig, WarehouseCategoryType, WarehouseMetricType } from '../../types';
import ModalWrapper from '../modals/ModalWrapper';
import { Icon } from '../common/Icon';
import SearchableSelect from '../common/SearchableSelect';
import { WAREHOUSE_METRIC_TYPE_MAP, WAREHOUSE_HEADER_COLORS, DEFAULT_WAREHOUSE_COLUMNS } from '../../constants';

interface SettingsModalProps {
    isOpen: boolean;
    onClose: () => void;
    columns: WarehouseColumnConfig[];
    onSave: (newColumns: WarehouseColumnConfig[]) => void;
    allIndustries: string[];
    allGroups: string[];
    allManufacturers: string[];
}

const WarehouseSettingsModal: React.FC<SettingsModalProps> = ({ isOpen, onClose, columns, onSave, allIndustries, allGroups, allManufacturers }) => {
    const [internalColumns, setInternalColumns] = useState<WarehouseColumnConfig[]>([]);
    const [view, setView] = useState<'picker' | 'form'>('picker');

    // Form state
    const [editingColumn, setEditingColumn] = useState<WarehouseColumnConfig | null>(null);
    const [mainHeader, setMainHeader] = useState('');
    const [subHeader, setSubHeader] = useState('');
    const [categoryType, setCategoryType] = useState<WarehouseCategoryType>('industry');
    const [categoryName, setCategoryName] = useState('');
    const [manufacturerName, setManufacturerName] = useState('');
    const [productCodesInput, setProductCodesInput] = useState<string>('');
    const [metricType, setMetricType] = useState<WarehouseMetricType>('quantity');

    const mainHeaderInputRef = useRef<HTMLInputElement>(null);

    useEffect(() => {
        if (isOpen) {
            const sortedColumns = [...columns].sort((a, b) => a.order - b.order);
            setInternalColumns(sortedColumns);
            setView('picker');
            resetForm(false);
        }
    }, [isOpen, columns]);

    useEffect(() => {
        if (view === 'form' && editingColumn === null) {
            mainHeaderInputRef.current?.focus();
        }
    }, [view, editingColumn]);

    const groupedColumns = useMemo(() => {
        return internalColumns.reduce<Record<string, WarehouseColumnConfig[]>>((acc, col) => {
            const key = col.mainHeader || 'Chưa phân loại';
            if (!acc[key]) {
                acc[key] = [];
            }
            acc[key].push(col);
            return acc;
        }, {});
    }, [internalColumns]);

    const resetForm = (switchToPicker = true) => {
        setEditingColumn(null);
        setMainHeader(''); setSubHeader(''); setCategoryType('industry');
        setCategoryName(''); setManufacturerName(''); setMetricType('quantity');
        setProductCodesInput('');
        if (switchToPicker) {
            setView('picker');
        }
    };

    const handleEdit = (column: WarehouseColumnConfig) => {
        setEditingColumn(column);
        setMainHeader(column.mainHeader);
        setSubHeader(column.subHeader);
        setCategoryType(column.categoryType || 'industry');
        setCategoryName(column.categoryName || '');
        setManufacturerName(column.manufacturerName || '');
        setProductCodesInput(column.productCodes?.join(', ') || '');
        setMetricType(column.metricType || 'quantity');
        setView('form');
    };

    const handleSaveAndClose = () => {
        const reorderedColumns = internalColumns.map((c, i) => ({ ...c, order: i }));
        onSave(reorderedColumns);
        onClose();
    };

    const handleToggleVisibility = (id: string) => {
        setInternalColumns(prev => prev.map(c => c.id === id ? { ...c, isVisible: !c.isVisible } : c));
    };

    const handleDelete = (id: string) => {
        if (window.confirm('Bạn có chắc chắn muốn xóa cột tùy chỉnh này?')) {
            setInternalColumns(prev => prev.filter(c => c.id !== id));
        }
    };

    const handleDeleteGroup = (groupName: string) => {
        if (window.confirm(`Bạn có chắc chắn muốn xóa nhóm "${groupName}" và tất cả các cột bên trong?`)) {
            setInternalColumns(prev => prev.filter(c => c.mainHeader !== groupName));
        }
    };

    const handleToggleGroupVisibility = (mainHeader: string, shouldBeVisible: boolean) => {
        setInternalColumns(prev => prev.map(c => c.mainHeader === mainHeader ? { ...c, isVisible: shouldBeVisible } : c));
    };

    const handleSaveColumn = (e: React.FormEvent) => {
        e.preventDefault();

        if (!mainHeader.trim() || !subHeader.trim()) {
            alert('Vui lòng điền đầy đủ Tiêu đề chính và Tiêu đề phụ.');
            return;
        }

        const productCodes = productCodesInput.split(/[\s,]+/).map(code => code.trim()).filter(Boolean);

        const newColumnData = {
            mainHeader: mainHeader.trim(), subHeader: subHeader.trim(), categoryType, 
            categoryName: categoryName || undefined, 
            manufacturerName: manufacturerName || undefined, 
            productCodes: productCodes.length > 0 ? productCodes : undefined,
            metricType 
        };

        if (editingColumn) {
            setInternalColumns(prev => prev.map(col => col.id === editingColumn.id ? { ...col, ...newColumnData } : col));
        } else {
            const newColumn: WarehouseColumnConfig = {
                id: `custom_${Date.now()}`,
                order: internalColumns.length, isVisible: true, isCustom: true,
                ...newColumnData
            };
            setInternalColumns(prev => [...prev, newColumn]);
        }
        resetForm();
    };

    const handleSelectAll = (select: boolean) => {
        setInternalColumns(prev => prev.map(c => ({...c, isVisible: select})));
    };

    const handleRestoreDefaults = () => {
        if (window.confirm('Thao tác này sẽ xóa tất cả các tùy chỉnh và khôi phục lại bố cục cột mặc định. Bạn có chắc chắn?')) {
            setInternalColumns([...DEFAULT_WAREHOUSE_COLUMNS]);
            resetForm();
        }
    };

    // Mapping colors for the picker UI - Updated for softer look
    const groupColorMap: Record<string, { bg: string, text: string, border: string }> = {
        'Doanh Thu': { bg: 'bg-blue-50/50 dark:bg-blue-900/10', text: 'text-blue-700 dark:text-blue-300', border: 'border-blue-100 dark:border-blue-800' },
        'TRAFFIC & TỶ LỆ TC/DT': { bg: 'bg-cyan-50/50 dark:bg-cyan-900/10', text: 'text-cyan-700 dark:text-cyan-300', border: 'border-cyan-100 dark:border-cyan-800' },
        'S.PHẨM CHÍNH': { bg: 'bg-teal-50/50 dark:bg-teal-900/10', text: 'text-teal-700 dark:text-teal-300', border: 'border-teal-100 dark:border-teal-800' },
        'SL BÁN KÈM': { bg: 'bg-violet-50/50 dark:bg-violet-900/10', text: 'text-violet-700 dark:text-violet-300', border: 'border-violet-100 dark:border-violet-800' },
        'DT THỰC NGÀNH HÀNG': { bg: 'bg-purple-50/50 dark:bg-purple-900/10', text: 'text-purple-700 dark:text-purple-300', border: 'border-purple-100 dark:border-purple-800' },
        'Phụ Kiện': { bg: 'bg-amber-50/50 dark:bg-amber-900/10', text: 'text-amber-700 dark:text-amber-300', border: 'border-amber-100 dark:border-amber-800' },
        'Gia Dụng': { bg: 'bg-orange-50/50 dark:bg-orange-900/10', text: 'text-orange-700 dark:text-orange-300', border: 'border-orange-100 dark:border-orange-800' },
        'DEFAULT': { bg: 'bg-slate-50/50 dark:bg-slate-800/30', text: 'text-slate-700 dark:text-slate-300', border: 'border-slate-100 dark:border-slate-700' },
