                <div className="flex items-center gap-1 p-0.5 bg-slate-100 dark:bg-slate-800 rounded-lg">
                    <button onClick={() => handleSelectAll(true)} className="px-3 py-1.5 text-[10px] font-bold text-slate-600 dark:text-slate-300 hover:bg-white dark:hover:bg-slate-700 rounded-md transition-all shadow-sm">Hiện tất cả</button>
                    <div className="w-px h-3 bg-slate-300 dark:bg-slate-600"></div>
