                </div>
                 <button onClick={() => { resetForm(false); setView('form'); }} className="flex items-center gap-1.5 px-4 py-1.5 rounded-lg text-xs font-bold text-white bg-indigo-600 hover:bg-indigo-700 active:scale-95 transition-all shadow-md shadow-indigo-200 dark:shadow-none">
                    <Icon name="plus" size={3.5} /> Thêm cột
                </button>
            </div>

             <div className="grid grid-cols-1 md:grid-cols-2 gap-4 pb-2">
                 {Object.entries(groupedColumns).map(([mainHeader, cols]) => {
                    if (!Array.isArray(cols)) return null;
                    const visibleCount = cols.filter(c => c.isVisible).length;
                    const isCustomGroup = cols.every(c => c.isCustom);
                    const styles = groupColorMap[mainHeader] || groupColorMap.DEFAULT;

                    return (
                        <div key={mainHeader} className={`group flex flex-col h-full rounded-2xl border ${styles.border} ${styles.bg} transition-all duration-300 hover:shadow-md overflow-hidden`}>
