                                    {isCustomGroup && (
                                        <button onClick={() => handleDeleteGroup(mainHeader)} title="Xóa nhóm" className="p-1 hover:bg-white dark:hover:bg-slate-700 text-red-500 rounded transition-colors"><Icon name="trash-2" size={3}/></button>
