                </div>
            </div>

            <div className="flex-grow overflow-y-auto pr-1 custom-scrollbar">
                <div className="bg-white dark:bg-slate-800 rounded-2xl border border-slate-200 dark:border-slate-700 p-5 space-y-5 shadow-sm">
                    {/* Compact Grid Layout for Inputs */}
                    <div className="grid grid-cols-2 gap-x-4 gap-y-5">
                        <div className="col-span-1">
                            <label className="block text-xs font-bold text-slate-500 dark:text-slate-400 mb-1.5">Tiêu đề nhóm (Cha)</label>
                            <input ref={mainHeaderInputRef} value={mainHeader} onChange={e => setMainHeader(e.target.value)} placeholder="VD: Phụ Kiện" className="w-full h-10 px-3 rounded-xl bg-slate-50 dark:bg-slate-900 border border-slate-200 dark:border-slate-700 focus:ring-2 focus:ring-indigo-500 focus:border-indigo-500 font-semibold text-sm transition-all" required />
                        </div>
                        <div className="col-span-1">
                            <label className="block text-xs font-bold text-slate-500 dark:text-slate-400 mb-1.5">Tiêu đề cột (Con)</label>
                            <input value={subHeader} onChange={e => setSubHeader(e.target.value)} placeholder="VD: SL Camera" className="w-full h-10 px-3 rounded-xl bg-slate-50 dark:bg-slate-900 border border-slate-200 dark:border-slate-700 focus:ring-2 focus:ring-indigo-500 focus:border-indigo-500 font-semibold text-sm transition-all" required />
                        </div>

                        <div className="col-span-1">
                            <label className="block text-xs font-bold text-slate-500 dark:text-slate-400 mb-1.5">Loại danh mục</label>
                            <div className="relative">
                                <select value={categoryType} onChange={e => { setCategoryType(e.target.value as WarehouseCategoryType); setCategoryName(''); }} className="w-full h-10 px-3 rounded-xl bg-slate-50 dark:bg-slate-900 border border-slate-200 dark:border-slate-700 focus:ring-2 focus:ring-indigo-500 focus:border-indigo-500 font-semibold text-sm appearance-none cursor-pointer">
                                    <option value="industry">Theo Ngành hàng (Lớn)</option>
                                    <option value="group">Theo Nhóm hàng (Nhỏ)</option>
                                </select>
                                <div className="absolute right-3 top-1/2 -translate-y-1/2 pointer-events-none text-slate-400"><Icon name="chevron-down" size={3.5}/></div>
                            </div>
                        </div>

                        <div className="col-span-1">
                             <SearchableSelect
                                label="Danh mục chính"
                                options={(categoryType === 'industry' ? allIndustries : allGroups)}
                                value={categoryName}
                                onChange={setCategoryName}
                                placeholder="Chọn danh mục"
                            />
                        </div>

                        <div className="col-span-1">
                            <label className="block text-xs font-bold text-slate-500 dark:text-slate-400 mb-1.5">Chỉ số tính</label>
                            <div className="flex rounded-xl bg-slate-100 dark:bg-slate-900 p-1 border border-slate-200 dark:border-slate-700 h-10">
                                {Object.entries(WAREHOUSE_METRIC_TYPE_MAP).map(([key, label]) => (
                                    <button
                                        type="button"
                                        key={key}
                                        onClick={() => setMetricType(key as WarehouseMetricType)}
                                        className={`flex-1 text-[10px] font-bold rounded-lg transition-all ${metricType === key ? 'bg-white dark:bg-slate-700 text-indigo-600 shadow-sm' : 'text-slate-500 hover:text-slate-700'}`}
                                    >
                                        {label}
                                    </button>
                                ))}
                            </div>
                        </div>

                        <div className="col-span-1">
                            <SearchableSelect
                                label="Nhà sản xuất (Tùy chọn)"
                                options={allManufacturers}
                                value={manufacturerName}
                                onChange={setManufacturerName}
                                placeholder="Tất cả"
                            />
                        </div>

                        <div className="col-span-2 border-t border-slate-100 dark:border-slate-800 pt-4 mt-2">
                            <label className="block text-xs font-bold text-slate-500 dark:text-slate-400 mb-2">
                                Mã sản phẩm (Nâng cao) 
                                <span className="font-normal italic opacity-70 ml-1">- Nhập mã cách nhau bằng dấu phẩy</span>
                            </label>
                            <textarea 
                                value={productCodesInput} 
                                onChange={e => setProductCodesInput(e.target.value)} 
                                placeholder="VD: 1234, 5678" 
                                rows={3} 
                                className="w-full p-3 rounded-xl bg-slate-50 dark:bg-slate-900 border border-slate-200 dark:border-slate-700 focus:ring-2 focus:ring-indigo-500 focus:border-indigo-500 font-mono text-xs transition-all resize-none" 
                            />
                        </div>
                    </div>
                </div>
            </div>

            <div className="pt-4 mt-4 border-t border-slate-200 dark:border-slate-700 flex gap-3">
                <button type="button" onClick={() => resetForm()} className="flex-1 h-11 rounded-xl font-bold text-sm text-slate-600 bg-slate-100 hover:bg-slate-200 dark:bg-slate-800 dark:text-slate-300 dark:hover:bg-slate-700 transition-all">
                    Hủy bỏ
                </button>
                <button type="submit" className="flex-1 h-11 rounded-xl font-bold text-sm text-white bg-indigo-600 hover:bg-indigo-700 active:scale-95 shadow-lg shadow-indigo-200 dark:shadow-none transition-all flex items-center justify-center gap-2">
                    <Icon name={editingColumn ? 'save' : 'plus'} size={4} />
                    {editingColumn ? 'Lưu thay đổi' : 'Thêm cột'}
                </button>
            </div>
        </form>
    );

    return (
        <ModalWrapper 
            isOpen={isOpen} 
            onClose={onClose} 
            title="Cấu Hình Cột Báo Cáo" 
            subTitle="Tùy chỉnh hiển thị dữ liệu kho" 
            titleColorClass="text-slate-800 dark:text-white" 
            maxWidthClass="max-w-4xl"
        >
            <div className="p-6 flex flex-col h-[75vh] max-h-[700px] bg-slate-50/50 dark:bg-slate-950/50 backdrop-blur-md">
                <div className="flex-grow overflow-y-auto custom-scrollbar px-1">
                   {view === 'picker' ? renderPickerView() : renderFormView()}
                </div>

                {view === 'picker' && (
                    <div className="pt-4 mt-4 border-t border-slate-200 dark:border-slate-700 flex justify-between items-center">
                        <button onClick={handleRestoreDefaults} className="text-[10px] font-bold text-slate-400 hover:text-amber-600 transition-colors flex items-center gap-1.5">
                            <Icon name="rotate-ccw" size={3} /> Khôi phục mặc định
                        </button>
                        <button onClick={handleSaveAndClose} className="px-6 py-3 rounded-xl text-sm font-bold text-white bg-slate-900 hover:bg-black dark:bg-white dark:text-slate-900 dark:hover:bg-slate-200 shadow-lg transition-all active:scale-95">
                            Hoàn tất & Đóng
                        </button>
                    </div>
                )}
            </div>
        </ModalWrapper>
    );
};

export default WarehouseSettingsModal;

import React, { useState, useRef, useEffect, useMemo } from 'react';
import type { WarehouseColumnConfig, WarehouseCategoryType, WarehouseMetricType } from '../../types';
import ModalWrapper from '../modals/ModalWrapper';
import { Icon } from '../common/Icon';
import SearchableSelect from '../common/SearchableSelect';
import { WAREHOUSE_METRIC_TYPE_MAP, DEFAULT_WAREHOUSE_COLUMNS } from '../../constants';

interface SettingsModalProps {
    isOpen: boolean;
    onClose: () => void;
    columns: WarehouseColumnConfig[];
    onSave: (newColumns: WarehouseColumnConfig[]) => void;
    allIndustries: string[];
    allGroups: string[];
    allManufacturers: string[];
}

const WarehouseSettingsModal: React.FC<SettingsModalProps> = ({ isOpen, onClose, columns, onSave, allIndustries, allGroups, allManufacturers }) => {
    const [internalColumns, setInternalColumns] = useState<WarehouseColumnConfig[]>([]);
    const [view, setView] = useState<'picker' | 'form'>('picker');

    // Form state
    const [editingColumn, setEditingColumn] = useState<WarehouseColumnConfig | null>(null);
    const [mainHeader, setMainHeader] = useState('');
    const [subHeader, setSubHeader] = useState('');
    const [categoryType, setCategoryType] = useState<WarehouseCategoryType>('industry');
    const [categoryName, setCategoryName] = useState('');
    const [manufacturerName, setManufacturerName] = useState('');
    const [productCodesInput, setProductCodesInput] = useState<string>('');
    const [metricType, setMetricType] = useState<WarehouseMetricType>('quantity');

    const mainHeaderInputRef = useRef<HTMLInputElement>(null);

    useEffect(() => {
        if (isOpen) {
            const sortedColumns = [...columns].sort((a, b) => a.order - b.order);
            setInternalColumns(sortedColumns);
            setView('picker');
            resetForm(false);
        }
    }, [isOpen, columns]);

    useEffect(() => {
        if (view === 'form' && editingColumn === null) {
            mainHeaderInputRef.current?.focus();
        }
    }, [view, editingColumn]);

    const groupedColumns = useMemo(() => {
        return internalColumns.reduce<Record<string, WarehouseColumnConfig[]>>((acc, col) => {
            const key = col.mainHeader || 'Khác';
            if (!acc[key]) {
                acc[key] = [];
            }
            acc[key].push(col);
            return acc;
        }, {});
    }, [internalColumns]);

    const resetForm = (switchToPicker = true) => {
        setEditingColumn(null);
        setMainHeader(''); setSubHeader(''); setCategoryType('industry');
        setCategoryName(''); setManufacturerName(''); setMetricType('quantity');
        setProductCodesInput('');
        if (switchToPicker) {
            setView('picker');
        }
    };

