                                        onClick={() => handleToggleVisibility(col.id)}
                                    >
                                        <div className={`w-1.5 h-1.5 rounded-full transition-colors ${col.isVisible ? styles.indicator : 'bg-slate-300 dark:bg-slate-600'}`}></div>
                                        <span className="truncate max-w-[130px] tracking-tight">{col.subHeader}</span>

                                        {col.isCustom && (
                                            <div className="flex items-center ml-1 pl-1 border-l border-slate-100 dark:border-slate-700 opacity-0 group-hover/item:opacity-100 transition-opacity">
                                                <button onClick={(e) => { e.stopPropagation(); handleEdit(col); }} className="p-0.5 hover:text-blue-500"><Icon name="edit-3" size={3} /></button>
                                                <button onClick={(e) => { e.stopPropagation(); handleDelete(col.id); }} className="p-0.5 hover:text-red-500"><Icon name="x" size={3} /></button>
                                            </div>
                                        )}
                                    </div>
                                ))}
                            </div>
                        </div>
                    )
                })}
            </div>
        </>
    );

    const renderFormView = () => (
        <form onSubmit={handleSaveColumn} className="flex flex-col h-full">
            <div className="flex items-center justify-between mb-6 pb-4 border-b border-slate-100 dark:border-slate-800">
                <div className="flex items-center gap-3">
                    <button type="button" onClick={() => resetForm()} className="p-2 rounded-full hover:bg-slate-100 dark:hover:bg-slate-800 transition-colors text-slate-500">
                        <Icon name="arrow-left" size={5} />
                    </button>
                    <div>
                        <h3 className="font-semibold text-lg text-slate-800 dark:text-slate-100 tracking-tight">{editingColumn ? 'Chỉnh sửa cột' : 'Tạo cột mới'}</h3>
                        <p className="text-xs text-slate-400 font-medium">{editingColumn ? editingColumn.subHeader : 'Thiết lập thông số cho cột báo cáo'}</p>
                    </div>
                </div>
            </div>

            <div className="flex-grow overflow-y-auto pr-2 custom-scrollbar">
                <div className="bg-white dark:bg-slate-800 rounded-[2rem] p-6 space-y-6 shadow-[0_4px_20px_-4px_rgba(0,0,0,0.03)] border border-slate-100 dark:border-slate-800">

                    <div className="grid grid-cols-2 gap-5">
                        <div className="col-span-1">
                            {/* Typography: Small, Uppercase, Widest tracking for labels */}
                            <label className="block text-[10px] font-bold text-slate-400 uppercase tracking-widest mb-2 ml-1">Nhóm (Cha)</label>
                            {/* Inputs: iOS style, gray background, borderless until focus */}
                            <input ref={mainHeaderInputRef} value={mainHeader} onChange={e => setMainHeader(e.target.value)} placeholder="VD: Phụ Kiện" className="w-full h-11 px-4 rounded-xl bg-slate-50 dark:bg-slate-900 border-none focus:ring-2 focus:ring-indigo-500/20 text-sm font-medium text-slate-700 placeholder:text-slate-400 transition-all" required />
                        </div>
                        <div className="col-span-1">
                            <label className="block text-[10px] font-bold text-slate-400 uppercase tracking-widest mb-2 ml-1">Cột (Con)</label>
                            <input value={subHeader} onChange={e => setSubHeader(e.target.value)} placeholder="VD: SL Camera" className="w-full h-11 px-4 rounded-xl bg-slate-50 dark:bg-slate-900 border-none focus:ring-2 focus:ring-indigo-500/20 text-sm font-medium text-slate-700 placeholder:text-slate-400 transition-all" required />
                        </div>

                        <div className="col-span-1">
                            <label className="block text-[10px] font-bold text-slate-400 uppercase tracking-widest mb-2 ml-1">Loại danh mục</label>
                            <div className="relative">
                                <select value={categoryType} onChange={e => { setCategoryType(e.target.value as WarehouseCategoryType); setCategoryName(''); }} className="w-full h-11 px-4 rounded-xl bg-slate-50 dark:bg-slate-900 border-none focus:ring-2 focus:ring-indigo-500/20 text-sm font-medium text-slate-700 appearance-none cursor-pointer">
                                    <option value="industry">Ngành hàng (Lớn)</option>
                                    <option value="group">Nhóm hàng (Nhỏ)</option>
                                </select>
                                <div className="absolute right-4 top-1/2 -translate-y-1/2 pointer-events-none text-slate-400"><Icon name="chevron-down" size={4}/></div>
                            </div>
                        </div>

                        <div className="col-span-1">
                             <SearchableSelect
                                label="Danh mục chính"
                                options={(categoryType === 'industry' ? allIndustries : allGroups)}
                                value={categoryName}
                                onChange={setCategoryName}
                                placeholder="Chọn danh mục"
                            />
                        </div>

                        <div className="col-span-1">
                            <label className="block text-[10px] font-bold text-slate-400 uppercase tracking-widest mb-2 ml-1">Chỉ số tính</label>
                            <div className="flex rounded-xl bg-slate-50 dark:bg-slate-900 p-1">
                                {Object.entries(WAREHOUSE_METRIC_TYPE_MAP).map(([key, label]) => (
                                    <button
                                        type="button"
                                        key={key}
                                        onClick={() => setMetricType(key as WarehouseMetricType)}
                                        className={`flex-1 py-2 text-[10px] font-bold uppercase tracking-wide rounded-lg transition-all ${metricType === key ? 'bg-white dark:bg-slate-700 text-indigo-600 shadow-sm' : 'text-slate-400 hover:text-slate-600'}`}
                                    >
                                        {label}
                                    </button>
                                ))}
                            </div>
                        </div>

                        <div className="col-span-1">
                            <SearchableSelect
                                label="Nhà sản xuất (Tùy chọn)"
                                options={allManufacturers}
                                value={manufacturerName}
                                onChange={setManufacturerName}
                                placeholder="Tất cả"
                            />
                        </div>

                        <div className="col-span-2 pt-2">
                            <label className="block text-[10px] font-bold text-slate-400 uppercase tracking-widest mb-2 ml-1">
                                Mã sản phẩm (Nâng cao) 
                            </label>
                            <textarea 
                                value={productCodesInput} 
                                onChange={e => setProductCodesInput(e.target.value)} 
                                placeholder="Nhập các mã nhóm hàng, cách nhau bằng dấu phẩy..." 
                                rows={3} 
                                className="w-full p-4 rounded-xl bg-slate-50 dark:bg-slate-900 border-none focus:ring-2 focus:ring-indigo-500/20 text-sm font-medium text-slate-700 placeholder:text-slate-400 transition-all resize-none" 
                            />
                        </div>
                    </div>
                </div>
            </div>

            <div className="pt-6 mt-2 border-t border-slate-100 dark:border-slate-800 flex gap-3">
                <button type="button" onClick={() => resetForm()} className="flex-1 h-12 rounded-xl font-semibold text-sm text-slate-500 bg-slate-50 hover:bg-slate-100 dark:bg-slate-800 dark:text-slate-400 dark:hover:bg-slate-700 transition-all">
                    Hủy bỏ
                </button>
                <button type="submit" className="flex-1 h-12 rounded-xl font-semibold text-sm text-white bg-slate-900 hover:bg-black dark:bg-white dark:text-slate-900 dark:hover:bg-slate-200 shadow-lg hover:shadow-xl transition-all flex items-center justify-center gap-2">
                    <Icon name={editingColumn ? 'save' : 'plus'} size={4} />
                    {editingColumn ? 'Lưu thay đổi' : 'Tạo cột'}
                </button>
            </div>
        </form>
    );

    return (
        <ModalWrapper 
            isOpen={isOpen} 
            onClose={onClose} 
            title="Cấu Hình Cột Báo Cáo" 
            subTitle="Tùy chỉnh hiển thị dữ liệu kho" 
            titleColorClass="text-slate-800 dark:text-white" 
            maxWidthClass="max-w-4xl"
        >
            <div className="p-6 flex flex-col h-[80vh] max-h-[750px] bg-[#FAFAFA]/50 dark:bg-slate-950/50 backdrop-blur-3xl">
                <div className="flex-grow overflow-y-auto custom-scrollbar px-1">
                   {view === 'picker' ? renderPickerView() : renderFormView()}
                </div>

                {view === 'picker' && (
                    <div className="pt-6 mt-2 border-t border-slate-200 dark:border-slate-700 flex justify-between items-center">
                        <button onClick={handleRestoreDefaults} className="text-[11px] font-semibold text-slate-400 hover:text-amber-600 transition-colors flex items-center gap-1.5">
                            <Icon name="rotate-ccw" size={3.5} /> Khôi phục mặc định
                        </button>
                        <button onClick={handleSaveAndClose} className="px-8 py-3 rounded-full text-xs font-bold uppercase tracking-wider text-white bg-slate-900 hover:bg-black dark:bg-white dark:text-slate-900 shadow-xl transition-all hover:scale-105 active:scale-95">
                            Hoàn tất & Đóng
                        </button>
                    </div>
                )}
            </div>
        </ModalWrapper>
    );
};

export default WarehouseSettingsModal;

import React, { useState, useRef, useEffect, useMemo } from 'react';
import type { WarehouseColumnConfig, WarehouseMetricType } from '../../types';
import { Icon } from '../common/Icon';
import { useDashboardContext } from '../../contexts/DashboardContext';
import { getWarehouseColumnConfig, saveWarehouseColumnConfig } from '../../services/dbService';
import { COL, WAREHOUSE_HEADER_COLORS, DEFAULT_WAREHOUSE_COLUMNS } from '../../constants';
import { getRowValue } from '../../utils/dataUtils';
import LoadingOverlay from '../common/LoadingOverlay';
import WarehouseSettingsModal from './WarehouseSettingsModal';
import { useWarehouseLogic } from '../../hooks/useWarehouseLogic';

interface WarehouseSummaryProps {
    onBatchExport: () => Promise<void>;
}

const WarehouseSummary: React.FC<WarehouseSummaryProps> = ({ onBatchExport }) => {
    const { processedData, productConfig, originalData, handleExport, isExporting, isProcessing, uniqueFilterOptions } = useDashboardContext();
    const data = processedData?.warehouseSummary ?? [];

    const summaryRef = useRef<HTMLDivElement>(null);
    const [sortConfig, setSortConfig] = useState<{ key: string; direction: 'asc' | 'desc' }>({ key: 'doanhThuQD', direction: 'desc' });
    const [isSettingsModalOpen, setIsSettingsModalOpen] = useState(false);

    const [columns, setColumns] = useState<WarehouseColumnConfig[]>([]);

    const { sortedData, totals, customTotals, customProductColumnValues, getColumnValue } = useWarehouseLogic({
        data,
        columns,
        originalData,
        productConfig,
        sortConfig
    });

    const getHqqdClass = (hqqdValue: number | undefined): string => {
        if (hqqdValue === undefined || isNaN(hqqdValue)) return 'text-slate-400 dark:text-slate-500';
        if (hqqdValue < 30) return 'text-rose-600 dark:text-rose-400 font-black';
        if (hqqdValue < 35) return 'text-amber-500 dark:text-amber-400 font-bold';
        return 'text-emerald-600 dark:text-emerald-400 font-black';
    };

    const getTraChamPercentClass = (percentage: number | undefined) => {
        if (percentage === undefined || isNaN(percentage)) return 'text-slate-400 dark:text-slate-500';
        if (percentage >= 45) return 'text-emerald-600 dark:text-emerald-400 font-bold';
        if (percentage >= 40) return 'text-amber-600 dark:text-amber-400 font-bold';
        return 'text-rose-600 dark:text-rose-400 font-black';
    };

    const formatRevenueForKho = (value: number | undefined): string => {
        if (value === undefined || isNaN(value) || value === 0) return '-';
        return Math.round(value / 1000000).toLocaleString('vi-VN');
    };

    const formatQuantityForKho = (value: number | undefined): string => {
        if (value === undefined || isNaN(value) || value === 0) return '-';
        return Math.round(value).toLocaleString('vi-VN');
    };

    const handleSingleExport = async () => {
        if (summaryRef.current) {
            await handleExport(summaryRef.current, 'bao-cao-kho.png', {
                elementsToHide: ['.hide-on-export'],
                captureAsDisplayed: true,
            });
        }
    };

    const { allIndustries, allGroups, allManufacturers } = useMemo(() => {
        if (!productConfig || !originalData) return { allIndustries: [], allGroups: [], allManufacturers: [] };
        const industries = new Set<string>();
        const groups = new Set<string>();
        Object.keys(productConfig.childToParentMap).forEach(childKey => industries.add(productConfig.childToParentMap[childKey]));
        Object.values(productConfig.subgroups).forEach(parent => Object.keys(parent).forEach(subgroup => groups.add(subgroup)));
        const dataRows = originalData;
        const manufacturers = new Set<string>(dataRows.map(row => getRowValue(row, COL.MANUFACTURER)).filter(Boolean));
        return { 
            allIndustries: Array.from(industries).sort(), 
            allGroups: Array.from(groups).sort(),
            allManufacturers: Array.from(manufacturers).sort(),
        };
    }, [productConfig, originalData]);

    useEffect(() => {
        const loadConfig = async () => {
            let config = await getWarehouseColumnConfig();
            if (!config || config.length === 0) {
                config = [...DEFAULT_WAREHOUSE_COLUMNS];
                await saveWarehouseColumnConfig(config);
            }
            setColumns(config);
        };
        loadConfig();
    }, [allIndustries, allGroups]);

    const handleSaveColumns = (newColumns: WarehouseColumnConfig[]) => {
        setColumns(newColumns);
        saveWarehouseColumnConfig(newColumns).catch(err => console.error("Failed to save column config:", err));
    };

    if (!data || data.length === 0) return null;

    const handleSort = (columnId: string) => {
        setSortConfig(prev => ({ key: columnId, direction: (prev?.key === columnId && prev.direction === 'desc') ? 'asc' : 'desc' }));
    };

    const visibleColumns = columns.filter(c => c.isVisible).sort((a,b) => a.order - b.order);

    const groupedHeaders = useMemo(() => {
        const groups: { name: string; colSpan: number; colorClass: string }[] = [];
        if (visibleColumns.length === 0) return groups;

        let currentGroup = { name: visibleColumns[0].mainHeader, colSpan: 1, colorClass: '' };

        const getGroupColor = (name: string) => {
             // Apple-like pastel palette mapping
             const map: Record<string, string> = {
                 'Doanh Thu': 'bg-blue-50/50 text-blue-700 dark:bg-blue-900/20 dark:text-blue-300',
                 'TRAFFIC & TỶ LỆ TC/DT': 'bg-orange-50/50 text-orange-700 dark:bg-orange-900/20 dark:text-orange-300',
                 'S.PHẨM CHÍNH': 'bg-teal-50/50 text-teal-700 dark:bg-teal-900/20 dark:text-teal-300',
                 'SL BÁN KÈM': 'bg-purple-50/50 text-purple-700 dark:bg-purple-900/20 dark:text-purple-300',
                 'DT THỰC NGÀNH HÀNG': 'bg-indigo-50/50 text-indigo-700 dark:bg-indigo-900/20 dark:text-indigo-300',
                 'Phụ Kiện': 'bg-pink-50/50 text-pink-700 dark:bg-pink-900/20 dark:text-pink-300',
                 'Gia Dụng': 'bg-cyan-50/50 text-cyan-700 dark:bg-cyan-900/20 dark:text-cyan-300',
             };
             return map[name] || 'bg-slate-50/50 text-slate-600 dark:bg-slate-800/30 dark:text-slate-400';
        };

        currentGroup.colorClass = getGroupColor(currentGroup.name);

        for (let i = 1; i < visibleColumns.length; i++) {
            if (visibleColumns[i].mainHeader === currentGroup.name) {
                currentGroup.colSpan++;
            } else {
                groups.push(currentGroup);
                currentGroup = { 
                    name: visibleColumns[i].mainHeader, 
                    colSpan: 1,
                    colorClass: getGroupColor(visibleColumns[i].mainHeader)
                };
            }
        }
        groups.push(currentGroup);
        return groups;
    }, [visibleColumns]);

    // Bento Design Helpers
    const getColumnBackground = (mainHeader: string) => {
         const map: Record<string, string> = {
             'Doanh Thu': 'bg-blue-50/20 dark:bg-blue-900/5',
             'TRAFFIC & TỶ LỆ TC/DT': 'bg-orange-50/20 dark:bg-orange-900/5',
             'S.PHẨM CHÍNH': 'bg-teal-50/20 dark:bg-teal-900/5',
             'SL BÁN KÈM': 'bg-purple-50/20 dark:bg-purple-900/5',
             'DT THỰC NGÀNH HÀNG': 'bg-indigo-50/20 dark:bg-indigo-900/5',
         };
         return map[mainHeader] || '';
    };

    return (
        <>
            <div id="warehouse-summary-view" className="bg-slate-50 dark:bg-black p-4 rounded-[2.5rem]" ref={summaryRef}>
                {(isProcessing || isExporting) && (
                    <div className="hide-on-export">
                        <LoadingOverlay />
                    </div>
                )}

                {/* BENTO HEADER */}
                <div className="flex flex-col md:flex-row justify-between items-start md:items-center gap-6 mb-6 px-2">
                    <div>
                        <div className="flex items-center gap-3 mb-1">
                            <div className="w-10 h-10 bg-black dark:bg-white rounded-xl flex items-center justify-center shadow-lg">
                                <Icon name="layout-grid" size={5} className="text-white dark:text-black"/>
                            </div>
                            <h2 className="text-2xl font-black text-slate-900 dark:text-white tracking-tight">Doanh Thu Tổng Hợp</h2>
                        </div>
                        <p className="text-xs font-bold text-slate-400 dark:text-slate-500 uppercase tracking-widest pl-1">Warehouse Performance Matrix</p>
                    </div>

                    <div className="flex items-center gap-2 hide-on-export bg-white dark:bg-slate-900 p-1.5 rounded-2xl shadow-sm border border-slate-200 dark:border-slate-800">
                        <button onClick={() => setIsSettingsModalOpen(true)} title="Tùy chỉnh cột" className="p-3 text-slate-500 hover:text-indigo-600 hover:bg-indigo-50 dark:hover:bg-indigo-900/30 rounded-xl transition-all">
                            <Icon name="settings-2" size={5} />
                        </button>
                        <div className="w-px h-6 bg-slate-200 dark:bg-slate-700 mx-1"></div>
                        <button onClick={handleSingleExport} disabled={isExporting} title="Xuất Ảnh" className="p-3 text-slate-500 hover:text-indigo-600 hover:bg-indigo-50 dark:hover:bg-indigo-900/30 rounded-xl transition-all">
                            {isExporting ? <Icon name="loader-2" className="animate-spin" /> : <Icon name="camera" size={5} />}
                        </button>
                        <button onClick={onBatchExport} disabled={isExporting || uniqueFilterOptions.kho.length <= 1} title="Xuất hàng loạt" className="p-3 bg-slate-900 dark:bg-white text-white dark:text-black rounded-xl shadow-lg hover:scale-105 active:scale-95 transition-all">
                            <Icon name="images" size={5} />
                        </button>
                    </div>
                </div>

                <div className="overflow-x-auto pb-4 custom-scrollbar">
                    <table className="w-full border-separate border-spacing-y-3">
                        {/* HEADERS */}
                        <thead>
                            {/* Group Headers (Pills) */}
                            <tr>
                                <th className="bg-transparent p-0"></th> <!-- Spacer for Kho Name -->
                                {groupedHeaders.map((group, index) => (
                                    <th key={index} colSpan={group.colSpan} className="p-1 pb-2">
                                        <div className={`text-[10px] font-black uppercase tracking-widest py-2 px-1 rounded-xl text-center ${group.colorClass}`}>
                                            {group.name}
                                        </div>
                                    </th>
                                ))}
                            </tr>

                            {/* Column Headers */}
                            <tr>
                                <th onClick={() => handleSort('khoName')} className="px-6 py-3 text-left text-xs font-black uppercase tracking-wider text-slate-400 cursor-pointer hover:text-slate-600 dark:hover:text-slate-200 transition-colors pl-8">
                                    Kho
                                </th>
                                {visibleColumns.map((col) => (
                                    <th key={col.id} onClick={() => handleSort(col.id)} className="px-2 py-3 text-center text-[10px] font-bold uppercase tracking-wider text-slate-400 cursor-pointer hover:text-indigo-500 transition-colors">
                                        {col.subHeader}
                                        {sortConfig.key === col.id && (
                                            <span className="ml-1 inline-block text-indigo-500">{sortConfig.direction === 'asc' ? '▲' : '▼'}</span>
                                        )}
                                    </th>
                                ))}
                            </tr>
                        </thead>

                        {/* BODY */}
                        <tbody>
                            {/* Floating Rows */}
                            {sortedData.map((row) => (
                                <tr key={row.khoName} data-kho-id={row.khoName} className="group bg-white dark:bg-[#1c1c1e] shadow-sm rounded-2xl hover:shadow-lg hover:scale-[1.002] transition-all duration-300">
                                    {/* Kho Name Cell (Sticky Look) */}
                                    <td className="py-5 px-6 rounded-l-2xl border-l-4 border-transparent group-hover:border-indigo-500 transition-all">
                                        <div className="flex items-center gap-3">
                                            <div className="w-8 h-8 rounded-full bg-slate-100 dark:bg-slate-800 flex items-center justify-center text-slate-500 font-bold text-xs">
                                                {row.khoName.substring(0, 1)}
                                            </div>
                                            <span className="font-black text-slate-700 dark:text-slate-200 text-sm">{row.khoName}</span>
                                        </div>
                                    </td>

                                    {/* Data Cells */}
                                    {visibleColumns.map((col, index) => {
                                        const value = (col.isCustom && col.productCodes) ? customProductColumnValues.get(col.id)?.get(row.khoName) : getColumnValue(row, col);
                                        const isLastCell = index === visibleColumns.length - 1;
                                        const cellBg = getColumnBackground(col.mainHeader);

                                        const isHqqd = col.metric === 'hieuQuaQD';
                                        const isTraChamPercent = col.metric === 'traChamPercent';
                                        const isRevenueColumn = col.metric === 'doanhThuThuc' || col.metric === 'doanhThuQD' || col.metricType === 'revenue' || col.metricType === 'revenueQD';

                                        let displayContent;
                                        if (isHqqd) {
                                            displayContent = <span className={`px-2 py-1 rounded-md text-xs ${getHqqdClass(value)} bg-white/50 dark:bg-black/20`}>{`${(value || 0).toFixed(0)}%`}</span>;
                                        } else if (isTraChamPercent) {
                                            displayContent = <span className={`text-xs ${getTraChamPercentClass(value)}`}>{`${value !== undefined ? value.toFixed(0) : '0'}%`}</span>;
                                        } else if (isRevenueColumn) {
                                            const isMainRevenue = col.metric === 'doanhThuQD' || col.metricType === 'revenueQD';
                                            displayContent = <span className={`${isMainRevenue ? 'font-black text-slate-800 dark:text-white text-base' : 'font-medium text-slate-500 dark:text-slate-400 text-sm'}`}>{formatRevenueForKho(value)}</span>;
                                        } else {
                                            displayContent = <span className='font-bold text-slate-600 dark:text-slate-300 text-sm'>{formatQuantityForKho(value)}</span>;
                                        }

                                        return (
                                            <td key={`${row.khoName}-${col.id}`} className={`py-4 px-2 text-center ${cellBg} ${isLastCell ? 'rounded-r-2xl' : ''}`}>
                                                {displayContent}
                                            </td>
                                        );
                                    })}
                                </tr>
                            ))}
                        </tbody>

                        {/* FOOTER (Summary Card) */}
                        <tfoot>
                             <tr className="h-4"></tr> {/* Spacer */}
                             <tr className="bg-slate-900 dark:bg-slate-800 text-white rounded-2xl shadow-xl transform scale-[1.01]">
                                <td className="py-6 px-6 rounded-l-2xl">
                                    <div className="flex items-center gap-2 text-amber-400">
                                        <Icon name="sigma" size={5} />
                                        <span className="font-black uppercase tracking-widest text-xs">Tổng Hệ Thống</span>
                                    </div>
                                </td>
                                {visibleColumns.map((col, index) => {
                                    const isHqqd = col.metric === 'hieuQuaQD';
                                    const isTraChamPercent = col.metric === 'traChamPercent';
                                    const value = isHqqd ? (totals as any).hieuQuaQD : isTraChamPercent ? (totals as any).traChamPercent : customTotals.get(col.id);
                                    const isLastCell = index === visibleColumns.length - 1;
                                    const isRevenueColumn = col.metric === 'doanhThuThuc' || col.metric === 'doanhThuQD' || col.metricType === 'revenue' || col.metricType === 'revenueQD';

                                    let displayContent;
                                    if (isHqqd) {
                                        displayContent = <span className={`font-black ${value < 35 ? 'text-red-400' : 'text-emerald-400'}`}>{`${(value || 0).toFixed(0)}%`}</span>;
                                    } else if (isTraChamPercent) {
                                        displayContent = <span className="font-bold text-slate-300">{`${value !== undefined ? value.toFixed(0) : '0'}%`}</span>;
                                    } else if (isRevenueColumn) {
                                        displayContent = <span className={`${col.metric === 'doanhThuQD' ? 'text-lg font-black text-white' : 'text-sm font-medium text-slate-400'}`}>{formatRevenueForKho(value)}</span>;
                                    } else {
                                        displayContent = <span className="font-bold text-slate-300">{formatQuantityForKho(value)}</span>;
                                    }

                                    return (
                                        <td key={`total-${col.id}`} className={`py-6 px-2 text-center ${isLastCell ? 'rounded-r-2xl' : ''}`}>
                                            {displayContent}
                                        </td>
                                    );
                                })}
                            </tr>
                        </tfoot>
                    </table>
                </div>
            </div>
             <WarehouseSettingsModal 
                isOpen={isSettingsModalOpen} 
                onClose={() => setIsSettingsModalOpen(false)}
                onSave={handleSaveColumns}
                columns={columns}
                allIndustries={allIndustries}
                allGroups={allGroups}
                allManufacturers={allManufacturers}
            />
        </>
    );
};

export default WarehouseSummary;

import React, { useState, useRef, useEffect, useMemo } from 'react';
import type { WarehouseColumnConfig, WarehouseMetricType } from '../../types';
import { Icon } from '../common/Icon';
import { useDashboardContext } from '../../contexts/DashboardContext';
import { getWarehouseColumnConfig, saveWarehouseColumnConfig } from '../../services/dbService';
import { COL, WAREHOUSE_HEADER_COLORS, DEFAULT_WAREHOUSE_COLUMNS } from '../../constants';
import { getRowValue } from '../../utils/dataUtils';
import LoadingOverlay from '../common/LoadingOverlay';
import WarehouseSettingsModal from './WarehouseSettingsModal';
import { useWarehouseLogic } from '../../hooks/useWarehouseLogic';

interface WarehouseSummaryProps {
    onBatchExport: () => Promise<void>;
}

const WarehouseSummary: React.FC<WarehouseSummaryProps> = ({ onBatchExport }) => {
    const { processedData, productConfig, originalData, handleExport, isExporting, isProcessing, uniqueFilterOptions } = useDashboardContext();
    const data = processedData?.warehouseSummary ?? [];

    const summaryRef = useRef<HTMLDivElement>(null);
    const [sortConfig, setSortConfig] = useState<{ key: string; direction: 'asc' | 'desc' }>({ key: 'doanhThuQD', direction: 'desc' });
    const [isSettingsModalOpen, setIsSettingsModalOpen] = useState(false);

    const [columns, setColumns] = useState<WarehouseColumnConfig[]>([]);

    const { sortedData, totals, customTotals, customProductColumnValues, getColumnValue } = useWarehouseLogic({
        data,
        columns,
        originalData,
        productConfig,
        sortConfig
    });

    const getHqqdClass = (hqqdValue: number | undefined): string => {
        if (hqqdValue === undefined || isNaN(hqqdValue)) return 'text-slate-400 dark:text-slate-500';
        if (hqqdValue < 30) return 'text-rose-600 dark:text-rose-400 font-black';
        if (hqqdValue < 35) return 'text-amber-500 dark:text-amber-400 font-bold';
        return 'text-emerald-600 dark:text-emerald-400 font-black';
    };

    const getTraChamPercentClass = (percentage: number | undefined) => {
        if (percentage === undefined || isNaN(percentage)) return 'text-slate-400 dark:text-slate-500';
        if (percentage >= 45) return 'text-emerald-600 dark:text-emerald-400 font-bold';
        if (percentage >= 40) return 'text-amber-600 dark:text-amber-400 font-bold';
        return 'text-rose-600 dark:text-rose-400 font-black';
    };

    const formatRevenueForKho = (value: number | undefined): string => {
        if (value === undefined || isNaN(value) || value === 0) return '-';
        return Math.round(value / 1000000).toLocaleString('vi-VN');
    };

    const formatQuantityForKho = (value: number | undefined): string => {
        if (value === undefined || isNaN(value) || value === 0) return '-';
        return Math.round(value).toLocaleString('vi-VN');
    };

    const handleSingleExport = async () => {
        if (summaryRef.current) {
            await handleExport(summaryRef.current, 'bao-cao-kho.png', {
                elementsToHide: ['.hide-on-export'],
                captureAsDisplayed: true,
            });
        }
    };

    const { allIndustries, allGroups, allManufacturers } = useMemo(() => {
        if (!productConfig || !originalData) return { allIndustries: [], allGroups: [], allManufacturers: [] };
        const industries = new Set<string>();
        const groups = new Set<string>();
        Object.keys(productConfig.childToParentMap).forEach(childKey => industries.add(productConfig.childToParentMap[childKey]));
        Object.values(productConfig.subgroups).forEach(parent => Object.keys(parent).forEach(subgroup => groups.add(subgroup)));
        const dataRows = originalData;
        const manufacturers = new Set<string>(dataRows.map(row => getRowValue(row, COL.MANUFACTURER)).filter(Boolean));
        return { 
            allIndustries: Array.from(industries).sort(), 
            allGroups: Array.from(groups).sort(),
            allManufacturers: Array.from(manufacturers).sort(),
        };
    }, [productConfig, originalData]);

    useEffect(() => {
        const loadConfig = async () => {
            let config = await getWarehouseColumnConfig();
            if (!config || config.length === 0) {
                config = [...DEFAULT_WAREHOUSE_COLUMNS];
                await saveWarehouseColumnConfig(config);
            }
            setColumns(config);
        };
        loadConfig();
    }, [allIndustries, allGroups]);

    const handleSaveColumns = (newColumns: WarehouseColumnConfig[]) => {
        setColumns(newColumns);
        saveWarehouseColumnConfig(newColumns).catch(err => console.error("Failed to save column config:", err));
    };

    if (!data || data.length === 0) return null;

    const handleSort = (columnId: string) => {
        setSortConfig(prev => ({ key: columnId, direction: (prev?.key === columnId && prev.direction === 'desc') ? 'asc' : 'desc' }));
    };

    const visibleColumns = columns.filter(c => c.isVisible).sort((a,b) => a.order - b.order);

    const groupedHeaders = useMemo(() => {
        const groups: { name: string; colSpan: number; colorClass: string }[] = [];
        if (visibleColumns.length === 0) return groups;

        let currentGroup = { name: visibleColumns[0].mainHeader, colSpan: 1, colorClass: '' };

        const getGroupColor = (name: string) => {
             // Apple-like pastel palette mapping
             const map: Record<string, string> = {
                 'Doanh Thu': 'bg-blue-50/50 text-blue-700 dark:bg-blue-900/20 dark:text-blue-300',
                 'TRAFFIC & TỶ LỆ TC/DT': 'bg-orange-50/50 text-orange-700 dark:bg-orange-900/20 dark:text-orange-300',
                 'S.PHẨM CHÍNH': 'bg-teal-50/50 text-teal-700 dark:bg-teal-900/20 dark:text-teal-300',
                 'SL BÁN KÈM': 'bg-purple-50/50 text-purple-700 dark:bg-purple-900/20 dark:text-purple-300',
                 'DT THỰC NGÀNH HÀNG': 'bg-indigo-50/50 text-indigo-700 dark:bg-indigo-900/20 dark:text-indigo-300',
                 'Phụ Kiện': 'bg-pink-50/50 text-pink-700 dark:bg-pink-900/20 dark:text-pink-300',
                 'Gia Dụng': 'bg-cyan-50/50 text-cyan-700 dark:bg-cyan-900/20 dark:text-cyan-300',
             };
             return map[name] || 'bg-slate-50/50 text-slate-600 dark:bg-slate-800/30 dark:text-slate-400';
        };

        currentGroup.colorClass = getGroupColor(currentGroup.name);

        for (let i = 1; i < visibleColumns.length; i++) {
            if (visibleColumns[i].mainHeader === currentGroup.name) {
                currentGroup.colSpan++;
            } else {
                groups.push(currentGroup);
                currentGroup = { 
                    name: visibleColumns[i].mainHeader, 
                    colSpan: 1,
                    colorClass: getGroupColor(visibleColumns[i].mainHeader)
                };
            }
        }
        groups.push(currentGroup);
        return groups;
    }, [visibleColumns]);

    // Bento Design Helpers
    const getColumnBackground = (mainHeader: string) => {
         const map: Record<string, string> = {
             'Doanh Thu': 'bg-blue-50/20 dark:bg-blue-900/5',
             'TRAFFIC & TỶ LỆ TC/DT': 'bg-orange-50/20 dark:bg-orange-900/5',
             'S.PHẨM CHÍNH': 'bg-teal-50/20 dark:bg-teal-900/5',
             'SL BÁN KÈM': 'bg-purple-50/20 dark:bg-purple-900/5',
             'DT THỰC NGÀNH HÀNG': 'bg-indigo-50/20 dark:bg-indigo-900/5',
         };
         return map[mainHeader] || '';
    };

    return (
        <>
            <div id="warehouse-summary-view" className="bg-slate-50 dark:bg-black p-4 rounded-[2.5rem]" ref={summaryRef}>
                {(isProcessing || isExporting) && (
                    <div className="hide-on-export">
                        <LoadingOverlay />
                    </div>
                )}

                {/* BENTO HEADER */}
                <div className="flex flex-col md:flex-row justify-between items-start md:items-center gap-6 mb-6 px-2">
                    <div>
                        <div className="flex items-center gap-3 mb-1">
                            <div className="w-10 h-10 bg-black dark:bg-white rounded-xl flex items-center justify-center shadow-lg">
                                <Icon name="layout-grid" size={5} className="text-white dark:text-black"/>
                            </div>
                            <h2 className="text-2xl font-black text-slate-900 dark:text-white tracking-tight">Doanh Thu Tổng Hợp</h2>
                        </div>
                        <p className="text-xs font-bold text-slate-400 dark:text-slate-500 uppercase tracking-widest pl-1">Warehouse Performance Matrix</p>
                    </div>

                    <div className="flex items-center gap-2 hide-on-export bg-white dark:bg-slate-900 p-1.5 rounded-2xl shadow-sm border border-slate-200 dark:border-slate-800">
                        <button onClick={() => setIsSettingsModalOpen(true)} title="Tùy chỉnh cột" className="p-3 text-slate-500 hover:text-indigo-600 hover:bg-indigo-50 dark:hover:bg-indigo-900/30 rounded-xl transition-all">
                            <Icon name="settings-2" size={5} />
                        </button>
                        <div className="w-px h-6 bg-slate-200 dark:bg-slate-700 mx-1"></div>
                        <button onClick={handleSingleExport} disabled={isExporting} title="Xuất Ảnh" className="p-3 text-slate-500 hover:text-indigo-600 hover:bg-indigo-50 dark:hover:bg-indigo-900/30 rounded-xl transition-all">
                            {isExporting ? <Icon name="loader-2" className="animate-spin" /> : <Icon name="camera" size={5} />}
                        </button>
                        <button onClick={onBatchExport} disabled={isExporting || uniqueFilterOptions.kho.length <= 1} title="Xuất hàng loạt" className="p-3 bg-slate-900 dark:bg-white text-white dark:text-black rounded-xl shadow-lg hover:scale-105 active:scale-95 transition-all">
                            <Icon name="images" size={5} />
                        </button>
                    </div>
                </div>

                <div className="overflow-x-auto pb-4 custom-scrollbar">
                    <table className="w-full border-separate border-spacing-y-3">
                        {/* HEADERS */}
                        <thead>
                            {/* Group Headers (Pills) */}
                            <tr>
                                <th className="bg-transparent p-0"></th>{/* Spacer for Kho Name */}
                                {groupedHeaders.map((group, index) => (
                                    <th key={index} colSpan={group.colSpan} className="p-1 pb-2">
                                        <div className={`text-[10px] font-black uppercase tracking-widest py-2 px-1 rounded-xl text-center ${group.colorClass}`}>
                                            {group.name}
                                        </div>
                                    </th>
                                ))}
                            </tr>

                            {/* Column Headers */}
                            <tr>
                                <th onClick={() => handleSort('khoName')} className="px-6 py-3 text-left text-xs font-black uppercase tracking-wider text-slate-400 cursor-pointer hover:text-slate-600 dark:hover:text-slate-200 transition-colors pl-8">
                                    Kho
                                </th>
                                {visibleColumns.map((col) => (
                                    <th key={col.id} onClick={() => handleSort(col.id)} className="px-2 py-3 text-center text-[10px] font-bold uppercase tracking-wider text-slate-400 cursor-pointer hover:text-indigo-500 transition-colors">
                                        {col.subHeader}
                                        {sortConfig.key === col.id && (
                                            <span className="ml-1 inline-block text-indigo-500">{sortConfig.direction === 'asc' ? '▲' : '▼'}</span>
                                        )}
                                    </th>
                                ))}
                            </tr>
                        </thead>

                        {/* BODY */}
                        <tbody>
                            {/* Floating Rows */}
                            {sortedData.map((row) => (
                                <tr key={row.khoName} data-kho-id={row.khoName} className="group bg-white dark:bg-[#1c1c1e] shadow-sm rounded-2xl hover:shadow-lg hover:scale-[1.002] transition-all duration-300">
                                    {/* Kho Name Cell (Sticky Look) */}
                                    <td className="py-5 px-6 rounded-l-2xl border-l-4 border-transparent group-hover:border-indigo-500 transition-all">
                                        <div className="flex items-center gap-3">
                                            <div className="w-8 h-8 rounded-full bg-slate-100 dark:bg-slate-800 flex items-center justify-center text-slate-500 font-bold text-xs">
                                                {row.khoName.substring(0, 1)}
                                            </div>
                                            <span className="font-black text-slate-700 dark:text-slate-200 text-sm">{row.khoName}</span>
                                        </div>
                                    </td>

                                    {/* Data Cells */}
                                    {visibleColumns.map((col, index) => {
                                        const value = (col.isCustom && col.productCodes) ? customProductColumnValues.get(col.id)?.get(row.khoName) : getColumnValue(row, col);
                                        const isLastCell = index === visibleColumns.length - 1;
                                        const cellBg = getColumnBackground(col.mainHeader);

                                        const isHqqd = col.metric === 'hieuQuaQD';
                                        const isTraChamPercent = col.metric === 'traChamPercent';
                                        const isRevenueColumn = col.metric === 'doanhThuThuc' || col.metric === 'doanhThuQD' || col.metricType === 'revenue' || col.metricType === 'revenueQD';

                                        let displayContent;
                                        if (isHqqd) {
                                            displayContent = <span className={`px-2 py-1 rounded-md text-xs ${getHqqdClass(value)} bg-white/50 dark:bg-black/20`}>{`${(value || 0).toFixed(0)}%`}</span>;
                                        } else if (isTraChamPercent) {
                                            displayContent = <span className={`text-xs ${getTraChamPercentClass(value)}`}>{`${value !== undefined ? value.toFixed(0) : '0'}%`}</span>;
                                        } else if (isRevenueColumn) {
                                            const isMainRevenue = col.metric === 'doanhThuQD' || col.metricType === 'revenueQD';
                                            displayContent = <span className={`${isMainRevenue ? 'font-black text-slate-800 dark:text-white text-base' : 'font-medium text-slate-500 dark:text-slate-400 text-sm'}`}>{formatRevenueForKho(value)}</span>;
                                        } else {
                                            displayContent = <span className='font-bold text-slate-600 dark:text-slate-300 text-sm'>{formatQuantityForKho(value)}</span>;
                                        }

                                        return (
                                            <td key={`${row.khoName}-${col.id}`} className={`py-4 px-2 text-center ${cellBg} ${isLastCell ? 'rounded-r-2xl' : ''}`}>
                                                {displayContent}
                                            </td>
                                        );
                                    })}
                                </tr>
                            ))}
                        </tbody>

                        {/* FOOTER (Summary Card) */}
                        <tfoot>
                             <tr className="h-4"></tr> {/* Spacer */}
                             <tr className="bg-slate-900 dark:bg-slate-800 text-white rounded-2xl shadow-xl transform scale-[1.01]">
                                <td className="py-6 px-6 rounded-l-2xl">
                                    <div className="flex items-center gap-2 text-amber-400">
                                        <Icon name="sigma" size={5} />
                                        <span className="font-black uppercase tracking-widest text-xs">Tổng Hệ Thống</span>
                                    </div>
                                </td>
                                {visibleColumns.map((col, index) => {
                                    const isHqqd = col.metric === 'hieuQuaQD';
                                    const isTraChamPercent = col.metric === 'traChamPercent';
                                    const value = isHqqd ? (totals as any).hieuQuaQD : isTraChamPercent ? (totals as any).traChamPercent : customTotals.get(col.id);
                                    const isLastCell = index === visibleColumns.length - 1;
                                    const isRevenueColumn = col.metric === 'doanhThuThuc' || col.metric === 'doanhThuQD' || col.metricType === 'revenue' || col.metricType === 'revenueQD';

                                    let displayContent;
                                    if (isHqqd) {
                                        displayContent = <span className={`font-black ${value < 35 ? 'text-red-400' : 'text-emerald-400'}`}>{`${(value || 0).toFixed(0)}%`}</span>;
                                    } else if (isTraChamPercent) {
                                        displayContent = <span className="font-bold text-slate-300">{`${value !== undefined ? value.toFixed(0) : '0'}%`}</span>;
                                    } else if (isRevenueColumn) {
                                        displayContent = <span className={`${col.metric === 'doanhThuQD' ? 'text-lg font-black text-white' : 'text-sm font-medium text-slate-400'}`}>{formatRevenueForKho(value)}</span>;
                                    } else {
                                        displayContent = <span className="font-bold text-slate-300">{formatQuantityForKho(value)}</span>;
                                    }

                                    return (
                                        <td key={`total-${col.id}`} className={`py-6 px-2 text-center ${isLastCell ? 'rounded-r-2xl' : ''}`}>
                                            {displayContent}
                                        </td>
                                    );
                                })}
                            </tr>
                        </tfoot>
                    </table>
                </div>
            </div>
             <WarehouseSettingsModal 
                isOpen={isSettingsModalOpen} 
                onClose={() => setIsSettingsModalOpen(false)}
                onSave={handleSaveColumns}
                columns={columns}
                allIndustries={allIndustries}
                allGroups={allGroups}
                allManufacturers={allManufacturers}
            />
        </>
    );
};

export default WarehouseSummary;
